# Module providing geometric shapes with inheritance and interfaces

interface IDrawable:
    def draw(self) -> str: ...

interface IMeasurable:
    def measure(self) -> float: ...


@abstract
class Shape(IDrawable, IMeasurable):
    name: str

    def __init__(self, name: str):
        self.name = name

    @virtual
    def describe(self) -> str:
        return f"Shape: {self.name}"

    @abstract
    def area(self) -> float: ...

    @abstract
    def draw(self) -> str: ...

    @abstract
    def measure(self) -> float: ...


class Rectangle(Shape):
    width: float
    height: float

    def __init__(self, name: str, width: float, height: float):
        super().__init__(name)
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def draw(self) -> str:
        return f"Drawing rectangle {self.name}"

    @override
    def measure(self) -> float:
        return self.width + self.height

    @virtual
    def is_square(self) -> bool:
        return self.width == self.height


class Circle(Shape):
    radius: float

    def __init__(self, name: str, radius: float):
        super().__init__(name)
        self.radius = radius

    @override
    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def draw(self) -> str:
        return f"Drawing circle {self.name}"

    @override
    def measure(self) -> float:
        return 2.0 * 3.14159 * self.radius

