# Module providing factory classes with cross-module dependencies

from shapes import Shape, Rectangle, Circle, IMeasurable
from utils import Point, BorderStyle


class ShapeFactory:
    @static
    def create_rectangle(name: str, w: float, h: float) -> Rectangle:
        return Rectangle(name, w, h)

    @static
    def create_circle(name: str, r: float) -> Circle:
        return Circle(name, r)


class ShapeMetrics(IMeasurable):
    shapes: list[Shape]
    origin: Point

    def __init__(self, ox: float, oy: float):
        self.shapes = []
        self.origin = Point(ox, oy)

    def add_shape(self, s: Shape) -> None:
        self.shapes.append(s)

    @override
    def measure(self) -> float:
        total: float = 0.0
        for s in self.shapes:
            total += s.measure()
        return total

    def total_area(self) -> float:
        total: float = 0.0
        for s in self.shapes:
            total += s.area()
        return total

    def count_by_style(self) -> list[BorderStyle]:
        result: list[BorderStyle] = []
        for s in self.shapes:
            if len(result) == 0:
                result.append(BorderStyle.SOLID)
            elif len(result) == 1:
                result.append(BorderStyle.DASHED)
            else:
                result.append(BorderStyle.DOTTED)
        return result
